class Solution {
public:
    int strangePrinter(string s) {
        int n = s.size();
        vector<vector<int>> dp(n, vector<int>(n, 0));
        for (int i = n - 1; i >= 0; --i) {
            dp[i][i] = 1;
            for (int j = i + 1; j < n; ++j) {
                if (s[i] == s[j]) {
                    dp[i][j] = dp[i + 1][j];
                } else {
                    dp[i][j] = min(dp[i][k] + dp[k + 1][j] for k in range(i, j));
                }
            }
        }
        return dp[0][n - 1];
    }
};
```

